#include <bits/stdc++.h> 
using namespace std; 
int n; 
int a[100002];  
int dfs(int l,int r,int x){
    if(l>r) return 0;
    int minn=INT_MAX,minx;
    for(int i=l;i<=r;i++){
        if(minn>a[i]){
            minn=a[i];
            minx=i;
        }
    }
    return dfs(l,minx-1,minn)+dfs(minx+1,r,minn)+(minn-x);
}
int main() 
{     
    cin >> n;
    for(int i = 1; i <= n; i++) cin >> a[i];
    cout<<dfs(1,n,0);
    return 0;
}
